 1→const UNITS = [
 2→  'B',
 3→  'KB',
 4→  'MB',
 5→  'GB',
 6→] as const;
 7→
 8→export function formatFileSize(bytes: number): string {
 9→  if (bytes === 0) return '--';
10→  let unitIndex = 0;
11→  let size = bytes;
12→  while (size >= 1024 && unitIndex < UNITS.length - 1) {
13→    size /= 1024;
14→    unitIndex++;
15→  }
16→  const formatted =
17→    unitIndex === 0 ? `${size}` : size.toFixed(size < 10 ? 1 : 0);
18→  return `${formatted} ${UNITS[unitIndex]}`;
19→}
