314→      meta: true,
315→    },
316→    handleCopyPath,
317→  );
318→  useKeyboardShortcut(
319→    {
320→      key: 'f',
321→      meta: true,
322→      shift: true,
323→    },
324→    handleShowInFinder,
325→  );
326→  useKeyboardShortcut(
327→    {
328→      key: 'Backspace',
329→      meta: true,
330→    },
331→    handleDelete,
332→  );
333→
334→  const dropdownSections: DropdownSection[] = useMemo(
335→    () => [
336→      {
337→        title: 'Actions',
338→        actions: [
339→          {
340→            label: 'Open',
341→            shortcut: <Kbd keys={['↵']} />,
342→            onClick: handleOpen,
343→          },
344→          {
345→            label: 'Show in Finder',
346→            shortcut: (
347→              <Kbd
348→                keys={[
349→                  '⌘',
350→                  '⇧',
351→                  'F',
352→                ]}
353→              />
354→            ),
355→            onClick: handleShowInFinder,
356→          },
357→          {
358→            label: 'Copy Path',
359→            shortcut: (
360→              <Kbd
361→                keys={[
