380→                  '⌫',
381→                ]}
382→              />
383→            ),
384→            onClick: handleDelete,
385→          },
386→        ],
387→      },
388→    ],
389→    [
390→      handleOpen,
391→      handleShowInFinder,
392→      handleCopyPath,
393→      handleDelete,
394→    ],
395→  );
396→
397→  const activeDescendantId =
398→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
399→
400→  function renderFileItem(entry: FileEntry, idx: number): ReactNode {
401→    const sizeText = formatFileSize(entry.size);
402→    return (
403→      <ListItem
404→        key={entry.id}
405→        index={idx}
406→        icon={getFileIcon(entry.fileType)}
407→        title={entry.name}
408→        subtitle={entry.path}
409→        accessories={[
410→          {
411→            tag: {
412→              text: FILE_TYPE_LABELS[entry.fileType],
413→              color:
414→                entry.fileType === 'folder'
415→                  ? 'blue'
416→                  : entry.fileType === 'code'
417→                    ? 'purple'
418→                    : entry.fileType === 'image'
419→                      ? 'green'
420→                      : undefined,
421→            },
422→          },
423→          { text: sizeText },
424→          {
425→            text: formatRelativeDate(entry.modifiedAt, now),
426→            tooltip: entry.modifiedAt.toLocaleString(),
427→          },
428→        ]}
429→      />
430→    );
431→  }
432→
433→  return (
434→    <>
435→      <SearchBar
436→        value={query}
437→        onChange={handleQueryChange}
438→        placeholder="Search Files..."
439→        activeDescendantId={activeDescendantId}
440→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
441→        dropdown={
442→          <SearchDropdown
443→            sections={FILTER_SECTIONS}
444→            value={filterValue}
445→            onChange={handleFilterChange}
446→          />
447→        }
448→      />
449→      <div className="command-palette__body">
450→        <div className="command-palette__list-container">
451→          {totalItemCount === 0 ? (
452→            <EmptyState
453→              icon={<SearchEmptyIcon />}
454→              title="No Results"
455→              description="Try a different search term or filter"
456→            />
457→          ) : (
458→            <List
459→              itemCount={totalItemCount}
460→              onActiveIndexChange={handleActiveIndexChange}
461→              onAction={handleAction}
462→            >
463→              {(() => {
464→                let globalIndex = 0;
465→                const sections: ReactNode[] = [];
466→
467→                if (folders.length > 0) {
468→                  sections.push(
469→                    <ListSection key="folders" title="Folders">
470→                      {folders.map(entry =>
471→                        renderFileItem(entry, globalIndex++))}
472→                    </ListSection>,
473→                  );
474→                }
475→
476→                if (files.length > 0) {
477→                  sections.push(
478→                    <ListSection key="files" title="Files">
479→                      {files.map(entry => renderFileItem(entry, globalIndex++))}
480→                    </ListSection>,
481→                  );
482→                }
483→
484→                return sections;
485→              })()}
486→            </List>
487→          )}
488→        </div>
489→      </div>
490→      <ActionPanel
491→        contextLabel="File Search"
492→        actions={[
493→          {
494→            label: 'Open',
495→            shortcut: <Kbd keys={['↵']} />,
496→          },
497→          {
498→            label: 'Actions',
499→            shortcut: (
500→              <Kbd
501→                keys={[
502→                  '⌘',
503→                  'K',
504→                ]}
505→              />
506→            ),
507→            onClick: toggleActions,
508→          },
509→        ]}
510→        dropdownOpen={actionsOpen}
511→        dropdownSections={dropdownSections}
512→        onDropdownClose={closeActions}
513→      />
514→      {alertState && (
515→        <Alert
516→          title={alertState.title}
517→          message={alertState.message}
518→          icon={alertState.icon}
519→          primaryAction={alertState.primaryAction}
520→          dismissAction={alertState.dismissAction}
521→          onDismiss={dismissAlert}
522→        />
523→      )}
524→      <HUDContainer items={hudItems} />
525→    </>
526→  );
527→}
